      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  var y = (new Date()).getFullYear();
  if (!f.getItemValue('den_ky')) f.setItemValues('den_ky, tu_nam, den_nam', [f.getItemValue('tu_ky'), y, y]);
  f.setReferenceKeyFilter('ma_pn');
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      g._alterTitle = [null, [['%p1', f.getItemValue('tu_ky'), true], ['%y1', f.getItemValue('tu_nam'), true],
        ['%p2', f.getItemValue('den_ky'), true], ['%y2', f.getItemValue('den_nam'), true]
      ]];

      var c = f.getItemValue('mau_bc');
      if (!g._v) g._v = c;
      if (g._v != c) {
        remove$GridReport$Filter(g);
        g._v = c;
      }
      break;
    default:
      break;
  }
}
function initForm(f) {
  var o = f.getItem('form'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255));
  for (var i = 0; i < value.length; i++) {
    o.options[i] = new Option(text[i], value[i]);
  }
}
function onChange$Filter$CategoryType(o) {o.parentForm.setReferenceKeyFilter('ma_pn');}
